import { vi } from 'vitest';
import { fetchHubSpotApi } from "../../../experimental/api-client/fetchHubSpotApi.js";
const mockFetchHubSpotApi = vi.fn();
Object.defineProperty(global, 'self', {
    value: {
        __HUBSPOT_EXTENSION_WORKER__: true,
        hsWorkerAPI: {
            fetchHubSpotApi: mockFetchHubSpotApi,
        },
    },
    writable: true,
});
describe('fetchHubSpotApi', () => {
    beforeEach(() => {
        vi.clearAllMocks();
    });
    describe('happy path', () => {
        it('forwards a minimal request to hsWorkerAPI and returns its response', async () => {
            const expected = { status: 200, headers: {}, body: { ok: true } };
            mockFetchHubSpotApi.mockResolvedValueOnce(expected);
            const result = await fetchHubSpotApi({
                path: '/crm/v3/objects/deals',
                method: 'GET',
            });
            expect(result).toEqual(expected);
            expect(mockFetchHubSpotApi).toHaveBeenCalledWith({
                path: '/crm/v3/objects/deals',
                method: 'GET',
            });
        });
        it('passes headers, contentType, and body through unchanged', async () => {
            mockFetchHubSpotApi.mockResolvedValueOnce({
                status: 201,
                headers: { 'X-Foo': 'bar' },
                body: { id: 1 },
            });
            const request = {
                path: '/crm/v3/objects/contacts',
                method: 'POST',
                headers: { Authorization: 'Bearer token' },
                contentType: 'application/json',
                body: { properties: { email: 'a@b.com' } },
            };
            await fetchHubSpotApi(request);
            expect(mockFetchHubSpotApi).toHaveBeenCalledWith(request);
        });
        it('rejects when the host runner rejects', async () => {
            mockFetchHubSpotApi.mockRejectedValueOnce(new Error('host failure'));
            await expect(fetchHubSpotApi({ path: '/foo', method: 'GET' })).rejects.toThrow('host failure');
        });
    });
    describe('validation', () => {
        it('rejects when path is missing', async () => {
            await expect(
            // @ts-expect-error testing invalid input
            fetchHubSpotApi({ method: 'GET' })).rejects.toThrow(/path must be a non-empty string that starts with \/; received: undefined/);
            expect(mockFetchHubSpotApi).not.toHaveBeenCalled();
        });
        it('rejects when path is empty', async () => {
            await expect(fetchHubSpotApi({ path: '', method: 'GET' })).rejects.toThrow(/path must be a non-empty string that starts with \/; received: ""/);
        });
        it('rejects when path does not start with /', async () => {
            await expect(fetchHubSpotApi({ path: 'crm/v3/objects/deals', method: 'GET' })).rejects.toThrow(/path must be a non-empty string that starts with \/; received: "crm\/v3\/objects\/deals"/);
        });
        it('rejects when path is not a string', async () => {
            await expect(
            // @ts-expect-error testing invalid input
            fetchHubSpotApi({ path: 123, method: 'GET' })).rejects.toThrow(/path must be a non-empty string that starts with \/; received: 123/);
        });
        it('rejects when method is invalid', async () => {
            await expect(
            // @ts-expect-error testing invalid input
            fetchHubSpotApi({ path: '/foo', method: 'OPTIONS' })).rejects.toThrow(/OPTIONS is not valid\. method must be one of GET, POST, PUT, PATCH, DELETE/);
        });
        it('rejects when headers are not a string record', async () => {
            await expect(fetchHubSpotApi({
                path: '/foo',
                method: 'GET',
                // @ts-expect-error testing invalid input
                headers: { 'X-Foo': 123 },
            })).rejects.toThrow(/headers must be an object whose values are all strings; received: \{"X-Foo":123\}/);
        });
        it('rejects when contentType is not a string', async () => {
            await expect(fetchHubSpotApi({
                path: '/foo',
                method: 'GET',
                // @ts-expect-error testing invalid input
                contentType: 123,
            })).rejects.toThrow(/contentType must be a string; received: 123/);
        });
        it('rejects when body is not a plain object', async () => {
            await expect(fetchHubSpotApi({
                path: '/foo',
                method: 'POST',
                // @ts-expect-error testing invalid input
                body: 'not-an-object',
            })).rejects.toThrow(/body must be a plain object; received: "not-an-object"/);
        });
        it('rejects when body is an array', async () => {
            await expect(fetchHubSpotApi({
                path: '/foo',
                method: 'POST',
                // @ts-expect-error testing invalid input
                body: [1, 2, 3],
            })).rejects.toThrow(/body must be a plain object; received: \[1,2,3\]/);
        });
    });
});
